class Solution(object):
    def sortVowels(self, s):
        vowels = set('aeiouAEIOU')
        extracted = sorted([c for c in s if c in vowels])
        res = list(s)
        vi = 0
        for i, c in enumerate(res):
            if c in vowels:
                res[i] = extracted[vi]
                vi += 1
        return ''.join(res)
